Without accounting for the `:active` state, it can be done with a ref and  `event.preventBaseUIHandler()`: https://codesandbox.io/p/sandbox/blissful-bouman-r2lvxg

```jsx
const MenuItemLink = React.forwardRef(function MenuItemLink(
  props: Menu.Item.Props & { href: string },
  forwardedRef: React.ForwardedRef<HTMLAnchorElement>
) {
  const { href, ...otherProps } = props;

  const linkRef = React.useRef<HTMLAnchorElement | null>(null);

  return (
    <Menu.Item
      ref={linkRef}
      render={<a />}
      href={href}
      target="_blank"
      onKeyDown={(event) => {
        const link = linkRef.current;
        if (!link) {
          return;
        }

        if (event.key === " ") {
          event.preventBaseUIHandler();
          link.click();
          // or router.navigate() etc
        }
      }}
      {...otherProps}
    />
  );
});
```
